import { BuiltLogic, Selector } from '../../types'
import { AtomicGraphNode, AtomicPluginContext, AtomicSelectorEntry, SelectorHealthReport, SelectorKind } from './types'

const ATOMIC_CONTEXT_KEY = 'atomicSelectors'

/** Lazily initialized per-context (getPluginContext creates a fresh {} object on every new context). */
export function getAtomicPluginContext(): AtomicPluginContext {
  const ctx = getPluginContext<Partial<AtomicPluginContext>>(ATOMIC_CONTEXT_KEY)
  if (!ctx.registry) {
    ctx.selectorFnToId = new WeakMap()
    ctx.registry = new Map()
    ctx.graph = new Map()
  }
  return ctx as AtomicPluginContext
}

function ensureGraphNode(graph: Map<string, AtomicGraphNode>, id: string): AtomicGraphNode {
  let node = graph.get(id)
  if (!node) {
    node = { id, dependsOn: new Set(), dependents: new Set() }
    graph.set(id, node)
  }
  return node
}

/** Get (creating if necessary) the registry entry for `${logic.pathString}.${localName}`. Stable
 * across Kea's build-time reassignment of the selector function itself. */
export function ensureSelectorEntry(logic: BuiltLogic, localName: string, kind: SelectorKind): AtomicSelectorEntry {
  const ctx = getAtomicPluginContext()
  const id = `${logic.pathString}.${localName}`
  let entry = ctx.registry.get(id)
  if (!entry) {
    entry = {
      id,
      logicPathString: logic.pathString,
      localName,
      kind,
      dependencies: [],
      evaluations: 0,
      dirtyCause: null,
      lastRawInputs: null,
      leavesByInputIndex: null,
      lastResult: undefined,
      hasRun: false,
    }
    ctx.registry.set(id, entry)
  } else {
    entry.kind = kind
  }
  ensureGraphNode(ctx.graph, id)
  return entry
}

/** Associate `selectorFn` (whichever function object Kea currently has assigned as
 * `logic.selectors[localName]`) with the stable id, so it can be resolved later when this
 * function is used as an input to another selector. */
export function registerSelectorIdentity(
  logic: BuiltLogic,
  localName: string,
  selectorFn: Selector,
  kind: SelectorKind,
): string {
  const entry = ensureSelectorEntry(logic, localName, kind)
  getAtomicPluginContext().selectorFnToId.set(selectorFn, entry.id)
  return entry.id
}

export function resolveSelectorId(fn: Selector): string | undefined {
  return getAtomicPluginContext().selectorFnToId.get(fn)
}

/** Record static (declaration-time) selector->selector edges for `id`, based on which of
 * `inputSelectors` resolve to other registered 'derived' selectors. */
export function setStaticDependencies(id: string, inputSelectors: Selector[]): void {
  const ctx = getAtomicPluginContext()
  const node = ensureGraphNode(ctx.graph, id)
  for (const inputFn of inputSelectors) {
    const depId = resolveSelectorId(inputFn)
    if (depId && depId !== id && ctx.registry.get(depId)?.kind === 'derived') {
      node.dependsOn.add(depId)
      ensureGraphNode(ctx.graph, depId).dependents.add(id)
    }
  }
}

/** 3-color DFS cycle detection over the static dependency graph, starting from `newIds`. Throws
 * synchronously (build time) the moment a cycle is found. */
export function checkForCycles(newIds: string[]): void {
  const ctx = getAtomicPluginContext()
  const color = new Map<string, 'gray' | 'black'>()

  function dfs(id: string, path: string[]): void {
    color.set(id, 'gray')
    path.push(id)
    const node = ctx.graph.get(id)
    if (node) {
      for (const depId of node.dependsOn) {
        if (color.get(depId) === 'gray') {
          const idx = path.indexOf(depId)
          const cycle = path.slice(idx).concat(depId)
          throw new Error(`[KEA] Circular dependency detected: ${cycle.join(' -> ')}`)
        }
        if (color.get(depId) !== 'black') {
          dfs(depId, path)
        }
      }
    }
    path.pop()
    color.set(id, 'black')
  }

  for (const id of newIds) {
    if (color.get(id) !== 'black') {
      dfs(id, [])
    }
  }
}

/** Topological sort (dependencies before dependents) restricted to the subgraph induced by `ids`. */
export function topoSortIds(ids: string[]): string[] {
  const ctx = getAtomicPluginContext()
  const idSet = new Set(ids)
  const visited = new Set<string>()
  const order: string[] = []

  function visit(id: string): void {
    if (visited.has(id)) return
    visited.add(id)
    const node = ctx.graph.get(id)
    if (node) {
      for (const depId of node.dependsOn) {
        if (idSet.has(depId)) visit(depId)
      }
    }
    order.push(id)
  }

  for (const id of ids) visit(id)
  return order
}

export function buildSelectorHealth(logic: BuiltLogic): () => SelectorHealthReport {
  return function selectorHealth(): SelectorHealthReport {
    const ctx = getAtomicPluginContext()
    const prefix = `${logic.pathString}.`
    const myIds = [...ctx.registry.keys()].filter(
      (id) => id.startsWith(prefix) && ctx.registry.get(id)!.kind === 'derived',
    )
    const selectorsReport: SelectorHealthReport['selectors'] = {}
    for (const id of myIds) {
      const entry = ctx.registry.get(id)!
      const node = ctx.graph.get(id)!
      selectorsReport[entry.localName] = {
        dependencies: [...entry.dependencies],
        dependents: [...node.dependents]
          .filter((depId) => ctx.registry.has(depId))
          .map((depId) => ctx.registry.get(depId)!.localName),
        evaluations: entry.evaluations,
        dirtyCause: entry.dirtyCause,
      }
    }
    return { selectors: selectorsReport, topologicalOrder: topoSortIds(myIds).map((id) => ctx.registry.get(id)!.localName) }
  }
}
