            accessedLeaves.push(leaf)
            return wrapForTracking(target.get(k), accessedLeaves, leaf)
          }
        }
        if (prop === 'has') {
          return (k: any) => {
            accessedLeaves.push(`${prefix ? prefix + '.' : ''}map:${String(k)}`)
            return target.has(k)
